  turnSpy: (officerId: EntityId, asDoubleAgent?: boolean) => { ok: boolean; message: string };
  issueEdict: (
    kind: EdictKind,
    targetForceId?: EntityId,
  ) => { ok: boolean; reason?: string; message?: string };
  promoteImperialRank: (
    forceId: EntityId,
    rank: ImperialRank,
  ) => { ok: boolean; reason?: string };
